import { useEffect, useState } from "react";
import API from "../api";

export default function Dashboard() {
	const [data, setData] = useState([]);

	const fetchData = async () => {
		const res = await API.get("/tickets/closed/all");
		setData(res.data);
	};

	useEffect(() => {
		fetchData();
	}, []);

	const deleteSeat = async (seat) => {
		await API.delete(`/tickets/${seat}`);
		fetchData();
	};

	return (
		<div>
			<h2>Dashboard</h2>

			<table border="1">
				<thead>
					<tr>
						<th>Name</th>
						<th>Seat</th>
						<th>Action</th>
					</tr>
				</thead>

				<tbody>
					{data.map((d) => (
						<tr key={d.seatNumber}>
							<td>{d.user?.name}</td>
							<td>{d.seatNumber}</td>
							<td>
								<button onClick={() => deleteSeat(d.seatNumber)}>Delete</button>
							</td>
						</tr>
					))}
				</tbody>
			</table>
		</div>
	);
}
